n = length(x);

for m = 1: 
    X = [];
    j=1;
    % Vi definerar matrisen i X*b = x dﻛr a ﻛr rekursionskoefficineterna.
    
    while j < n-m+1
        X = [X;x(j:m-1+j)];
        j = j + 1;
    end
    
    % Approximerar a genom minskakvadratmetoden
    modifierad_x = x(m + 1:n)';
    B = (X')*X; 
    b = B\(X'* modifierad_x);

    ursprunglig_signal = x(1:m);
    i = 1;
    
    % Skapar approximerad signal genom att anvﻛndaa a pﮒ x.
    while i < n-m+1
        approximerad_signal = ursprunglig_signal(i:m-1+i)*b;
        ursprunglig_signal = [ursprunglig_signal, approximerad_signal];
        i = i + 1;
    end
    % Vi definerar ljudet som skillnaden mellan den ursprungliga och
    % approximerade signalen.
    ljud = x - ursprunglig_signal; 
    norm = ljud*ljud';
    ljud_norm_vector(m) = norm;
%     varians = var(ljud);
%     varians_vektor(m) = varians;

end

% Finds the minimal value of the norm and then finds the corresponding 
% m-value
min_norm = min(ljud_norm_vector); 
optimal_m = find(ljud_norm_vector==min_norm)
% varians_vektor(optimal_m)
var(ljud)